import{c as a,Q as o,j as n,m as c}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"000-env-toolchain-1 · 环境搭建","description":"","frontmatter":{"title":"000-env-toolchain-1 · 环境搭建"},"headers":[],"relativePath":"hands-on/000-env-toolchain-1.md","filePath":"hands-on/000-env-toolchain-1.md","lastUpdated":1779686691000}'),s={name:"hands-on/000-env-toolchain-1.md"};function d(t,e,l,i,r,p){return o(),n("div",null,[...e[0]||(e[0]=[c(`<h1 id="_000-1-·-工具链安装与-cmake-构建系统" tabindex="-1">000-1 · 工具链安装与 CMake 构建系统 <a class="header-anchor" href="#_000-1-·-工具链安装与-cmake-构建系统" aria-label="Permalink to &quot;000-1 · 工具链安装与 CMake 构建系统&quot;">​</a></h1><blockquote><p><strong>本篇目标</strong>：安装 Cinux 开发所需的全部工具，编写检查脚本验证安装， 配置 CMake 构建系统的完整骨架（toolchain file + 顶层 CMakeLists.txt + QEMU 集成）。</p><p><strong>完成后的效果</strong>：<code>cmake -DCMAKE_BUILD_TYPE=Debug ..</code> 在 build 目录里 configure 成功， 终端打印构建配置摘要，所有编译器 flag 正确注入。</p><p><strong>前置知识</strong>：熟悉 Linux 命令行，有基本的 C/C++ 经验即可。</p></blockquote><hr><h2 id="前言-为什么要先折腾环境" tabindex="-1">前言：为什么要先折腾环境 <a class="header-anchor" href="#前言-为什么要先折腾环境" aria-label="Permalink to &quot;前言：为什么要先折腾环境&quot;">​</a></h2><p>搭建开发环境这件事，向来是劝退人。你在网上随便搜个 OS 开发教程， 十有八九都会告诉你&quot;先去编译一个交叉编译器&quot; （孩子们，如果你是跟着《操作系统还原真相》那本书走，你收货的是 gcc 4.6.2）， 然后丢给你一堆链接和命令，照着敲完也不知道自己到底干了什么。 等到后面编译报错、链接找不到符号、QEMU 起来就是黑屏的时候， 根本不知道问题出在哪，只能对着终端发呆。</p><p>笔者在折腾 Cinux 的时候也踩过不少这种坑。有些教程用 NASM 汇编器， 有些用 GRUB 引导加载，还有些直接给你一个 Docker 镜像让你&quot;感受一下&quot; ——这对于想理解从 MBR 到内核每一步到底发生了什么的人来说，简直是一种折磨。 如果你跟我一样想搞清楚从硬盘第一扇区开始， CPU 到底干了什么、内存里到底发生了什么， 那就必须从最基础的工具链开始，一步一步把环境搭起来， 搞清楚每一个编译 flag 的含义。</p><p>这一章做的事情看着很 boring：装几个包，写一个检查脚本，配一下 CMake。 但这些东西是后面写 bootloader 和内核的基石 ——现在偷懒跳过去，后面一定会加倍还回来。</p><p>好了，废话不多说，开始上号。</p><hr><h2 id="我们的环境" tabindex="-1">我们的环境 <a class="header-anchor" href="#我们的环境" aria-label="Permalink to &quot;我们的环境&quot;">​</a></h2><p>实验环境是一台 x86_64 Linux 机器（Ubuntu 22.04 或更新版本）， 工具链完全来自系统包管理器——不需要编译交叉编译器，不需要 Docker， 不需要任何特殊准备。GCC 版本要求 11+（支持 C++23 的基本特性）， CMake 笔者使用的是 4.1（实际 3.20 以上即可）， QEMU 要求 8.0+（模拟 x86_64 启动）。 编辑器随意，但如果用 VS Code 的话， 项目里已经配好了 clangd 支持（<code>compile_commands.json</code> 在 build 目录里自动生成）， 装上 clangd 插件就能获得代码补全和错误提示。</p><p>这里有一个值得展开说说的选择：为什么不用交叉编译器？ OSDev Wiki 上的 Bare Bones 教程强烈建议你构建一个 <code>x86_64-elf-gcc</code> 交叉编译器， 理由是系统 GCC 可能会隐式链接宿主系统的库、 假设宿主系统的 ABI、甚至生成一些在裸机上无法运行的代码。 这些担忧在理论上是成立的，但在实际操作中， 只要你加上 <code>-ffreestanding -nostdlib -static</code> 这些 flag， 系统 GCC 生成的代码在 x86_64 裸机上就是完全可用的 ——因为我们的宿主机本身就是 x86_64，指令集层面没有任何差异。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cinux 构建架构总览：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    cmake/toolchain-x86_64.cmake     &lt;- 编译 flag 注入</span></span>
<span class="line"><span>               |</span></span>
<span class="line"><span>               v</span></span>
<span class="line"><span>        CMakeLists.txt (顶层)         &lt;- 全局配置 + 子目录编排</span></span>
<span class="line"><span>        +-- add_subdirectory(boot)    &lt;- MBR 编译 -&gt; mbr.bin</span></span>
<span class="line"><span>        +-- add_subdirectory(kernel)  &lt;- 内核编译（后续 tag）</span></span>
<span class="line"><span>        +-- add_subdirectory(test)    &lt;- Host 端单元测试</span></span>
<span class="line"><span>        +-- include(cmake/qemu.cmake) &lt;- make run/run-debug target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    编译流水线（以 MBR 为例）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    mbr.S --+--&gt; mbr.o --+--&gt; mbr.elf --+--&gt; mbr.bin --+--&gt; cinux.img</span></span>
<span class="line"><span>     (汇编)    (AS -Wa,--32) (ld -m elf_i386) (objcopy -O binary)  (dd)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    辅助脚本：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    scripts/check_toolchain.sh  -&gt; 验证工具安装</span></span>
<span class="line"><span>    scripts/log/logging.sh      -&gt; 带颜色的日志函数</span></span>
<span class="line"><span>    scripts/build_image.sh      -&gt; dd 组装磁盘镜像</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><hr><h2 id="概念精讲-freestanding-vs-hosted" tabindex="-1">概念精讲：freestanding vs hosted <a class="header-anchor" href="#概念精讲-freestanding-vs-hosted" aria-label="Permalink to &quot;概念精讲：freestanding vs hosted&quot;">​</a></h2><h3 id="为什么写-os-内核不能用普通的方式编译" tabindex="-1">为什么写 OS 内核不能用普通的方式编译 <a class="header-anchor" href="#为什么写-os-内核不能用普通的方式编译" aria-label="Permalink to &quot;为什么写 OS 内核不能用普通的方式编译&quot;">​</a></h3><p>普通的应用程序开发，编译器默认帮你做了很多事情： 链接标准 C 库（glibc），假设操作系统提供了文件系统、 内存分配、线程调度等服务， 甚至帮你插入栈保护代码和异常处理表。 这些在写应用程序的时候是天经地义的， 但写内核的时候反而全是累赘 ——因为内核本身就是那个&quot;提供一切服务&quot;的东西， 它运行在没有任何操作系统支撑的裸机上， 连 <code>printf</code> 都没有，更别提什么 <code>malloc</code> 和 <code>std::vector</code> 了。</p><p>编译理论里把这两种环境分得很清楚： 有操作系统支撑的叫 <strong>hosted</strong>（托管环境）， 没有的叫 <strong>freestanding</strong>（独立环境）。 内核开发属于后者， 必须用一系列编译 flag 告诉编译器&quot;别自作聪明&quot;。</p><p>对比一下两种环境下的编译 flag 差异：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hosted (普通程序)           Freestanding (内核)</span></span>
<span class="line"><span>─────────────────────      ──────────────────────────────</span></span>
<span class="line"><span>默认链接 glibc              -ffreestanding -nostdlib</span></span>
<span class="line"><span>栈保护 canary               -fno-stack-protector</span></span>
<span class="line"><span>异常处理 .eh_frame          -fno-exceptions</span></span>
<span class="line"><span>RTTI (dynamic_cast)         -fno-rtti</span></span>
<span class="line"><span>Red zone 优化               -mno-red-zone</span></span>
<span class="line"><span>默认代码模型 small           -mcmodel=kernel</span></span>
<span class="line"><span>动态链接                     -static</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>每一个 flag 背后都有具体的技术原因。</p><p><code>-ffreestanding</code> 告诉编译器代码运行在没有操作系统的裸机环境， 只提供 freestanding 头文件（<code>&lt;stdint.h&gt;</code>, <code>&lt;stddef.h&gt;</code>, <code>&lt;stdarg.h&gt;</code> 等）， 不提供 <code>printf</code>、<code>malloc</code>。</p><p><code>-fno-stack-protector</code> 禁用栈保护， 因为栈保护的 canary 初始化依赖 <code>__stack_chk_fail</code> 函数， 这个函数需要标准库提供，内核里什么都没有。</p><p><code>-mno-red-zone</code> 禁用 x86_64 System V ABI 里的 red zone ——这是给用户态程序的一个 128 字节栈下空间优化， 允许函数在不调整 RSP 的情况下使用栈空间。 但在内核里，中断可能在任何时候打断执行（包括红区里的代码）， 如果用了 red zone，中断处理程序的栈帧会覆盖掉还没用完的数据， 直接导致数据损坏和难以调试的随机崩溃。</p><p><code>-mcmodel=kernel</code> 告诉编译器代码会运行在地址空间最顶端 （高半核，约 <code>0xFFFFFFFF80000000</code>）， 这影响了它生成绝对地址引用的方式。</p><p>C++ 特有的 flag 禁用了异常（<code>-fno-exceptions</code>）和 RTTI（<code>-fno-rtti</code>）。 为什么 OS 内核不能用异常？ 原因在于异常的展开（unwinding）需要 <code>.eh_frame</code> 段 和 <code>__cxa_begin_catch</code> 等运行时函数的支持， 这些都需要标准库提供。 而且异常展开会隐式调用析构函数， 这要求堆分配器已经初始化 ——但堆分配器本身就是内核的一部分，形成了循环依赖。</p><p>对比一下其他项目的做法也很有参考价值：</p><table tabindex="0"><thead><tr><th>项目</th><th>构建方案</th><th>复杂度</th></tr></thead><tbody><tr><td>xv6</td><td>裸 Makefile，flag 硬编码</td><td>低，但不可扩展</td></tr><tr><td>SerenityOS</td><td>30+ CMake 模块，多编译器多架构</td><td>高，工业级</td></tr><tr><td>Cinux</td><td>CMake + toolchain file，最小配置</td><td>中等，刚好够用</td></tr></tbody></table><hr><h2 id="step-1-安装并验证工具链" tabindex="-1">Step 1: 安装并验证工具链 <a class="header-anchor" href="#step-1-安装并验证工具链" aria-label="Permalink to &quot;Step 1: 安装并验证工具链&quot;">​</a></h2><p><strong>目标</strong>：安装 Cinux 开发所需的全部工具，确认版本满足要求。</p><p><strong>设计思路</strong>：Cinux 的构建依赖 GNU 工具链 （gcc, g++, as, ld, objcopy）和 QEMU 模拟器，构建系统使用 CMake。 我们需要确保这些工具都已安装且版本足够新 ——特别是 CMake 需要支持现代特性 （toolchain file、generator expressions 等）， GCC 需要支持 C++23 标准。 Cinux 还需要 <code>gcc-multilib</code> 或等价包来支持 32 位交叉汇编 ——bootloader 的 MBR 和 stage2 运行在 16 位和 32 位模式下， 需要用 32 位 ELF 格式链接（<code>-Wl,-m,elf_i386</code>）， 即使最终的 64 位内核不需要。</p><p><strong>实现约束</strong>：</p><p>需要编写两个 Shell 脚本。</p><p>第一个是日志模块 <code>scripts/log/logging.sh</code>， 它导出颜色变量（<code>LOG_RED</code>, <code>LOG_GREEN</code>, <code>LOG_YELLOW</code>, <code>LOG_NC</code>） 并定义四个日志函数： <code>log_info</code>（绿色 <code>[INFO]</code>）、 <code>log_error</code>（红色 <code>[ERROR]</code>，输出到 stderr）、 <code>log_warn</code>（黄色 <code>[WARN]</code>）和 <code>log_success</code>（绿色 <code>[SUCCESS]</code>）。 所有函数使用 ANSI 转义序列给终端输出加颜色， 脚本之间通过 <code>source</code> 命令引入复用。</p><p>第二个是检查脚本 <code>scripts/check_toolchain.sh</code>， 它先 <code>source</code> 日志模块， 然后逐个检查以下工具： <code>gcc</code>, <code>g++</code>, <code>as</code>（GNU 汇编器）, <code>ld</code>（链接器）, <code>objcopy</code>（二进制转换工具）, <code>qemu-system-x86_64</code>, <code>cmake</code>。 检查使用 <code>command -v</code> 检测命令是否存在， 不存在则打印缺失提示和安装命令后 <code>exit 1</code> 退出。 CMake 版本检查是单独的： 用 <code>cmake --version | head -n1 | grep -oP &#39;\\d+\\.\\d+&#39;</code> 提取版本号， 然后和最低要求做数值比较。 任何一个工具缺失都会终止脚本， 而不是继续往下检查 ——因为后续工具的检测可能依赖前面的工具。</p><p><strong>踩坑预警</strong>：如果你的系统没有安装 <code>gcc-multilib</code>， 在链接 32 位 bootloader 目标文件时会报 <code>cannot find -lgcc_s</code> 之类的错误。 因为 MBR 和 stage2 需要 32 位 ELF 链接， 即使目标是 64 位内核，32 位支持也不能少。 在 Ubuntu 上需要额外安装 <code>gcc-multilib</code> 和 <code>g++-multilib</code> 包。 这个报错信息完全不指向真正的原因，笔者在这里被坑了半天。</p><p><strong>验证</strong>：运行检查脚本（<code>./scripts/check_toolchain.sh</code>）， 预期看到每个工具后面都跟着绿色的 <code>[OK]</code> 标记， 最后一行显示 <code>[OK] All required tools are installed!</code>。 如果有任何工具缺失，脚本会打印对应的安装提示并退出。</p><hr><h2 id="step-2-配置-cmake-构建系统" tabindex="-1">Step 2: 配置 CMake 构建系统 <a class="header-anchor" href="#step-2-配置-cmake-构建系统" aria-label="Permalink to &quot;Step 2: 配置 CMake 构建系统&quot;">​</a></h2><p><strong>目标</strong>：搭建 CMake 项目骨架， 包括顶层 CMakeLists.txt、toolchain file 和 QEMU 集成。</p><p><strong>设计思路</strong>：Cinux 的构建系统采用三层结构： 顶层 <code>CMakeLists.txt</code> 负责项目全局配置 （最低版本、语言、编译选项、子目录）， <code>cmake/toolchain-x86_64.cmake</code> 定义裸机交叉编译的具体参数， <code>cmake/qemu.cmake</code> 注册 QEMU 相关的 make target （<code>make run</code>, <code>make run-debug</code> 等）。 这种分层设计让每个文件的职责非常清晰： toolchain file 管&quot;怎么编译&quot;， qemu.cmake 管&quot;怎么运行&quot;， 顶层 CMakeLists 管&quot;编译什么&quot;。</p><p><strong>实现约束</strong>：</p><p><strong>Toolchain file</strong> (<code>cmake/toolchain-x86_64.cmake</code>)： 这个文件是 CMake 交叉编译的核心。 它需要设置 <code>CMAKE_SYSTEM_NAME</code> 为 <code>Generic</code> （告诉 CMake 没有目标操作系统）、 <code>CMAKE_SYSTEM_PROCESSOR</code> 为 <code>x86_64</code>， 然后通过 <code>CMAKE_C_FLAGS_INIT</code>、<code>CMAKE_CXX_FLAGS_INIT</code>、 <code>CMAKE_ASM_FLAGS_INIT</code>、<code>CMAKE_EXE_LINKER_FLAGS_INIT</code> 注入编译和链接 flag。 注意这里必须用 <code>_INIT</code> 后缀而不是直接设 <code>CMAKE_C_FLAGS</code> ——<code>_INIT</code> 变量只在第一次 configure 时被读取， 之后用户可以通过命令行追加自定义 flag 而不会和 toolchain file 的 flag 冲突， 是 CMake 官方推荐的 toolchain file 写法。</p><p>链接器 flag 包括 <code>-nostdlib</code> （不链接标准启动文件和库）和 <code>-static</code> （纯静态链接不依赖动态链接器）。 最后通过 <code>CMAKE_FIND_ROOT_PATH_MODE_*</code> 设置查找策略： <code>PROGRAM NEVER</code> 表示 <code>find_program</code> 只在宿主系统搜索 （我们需要在宿主上找 CMake、objcopy 这些工具）， <code>LIBRARY ONLY</code> 和 <code>INCLUDE ONLY</code> 配合空的 <code>CMAKE_FIND_ROOT_PATH</code> 禁用所有库和头文件的自动查找， 内核项目必须手动指定所有依赖。</p><p><strong>顶层 CMakeLists.txt</strong>： 需要设置 CMake 最低版本 （笔者环境为 4.1，实际 3.20 以上即可）， 声明项目名称（<code>cinux</code>）、版本（<code>0.1.0</code>） 和使用的语言（C、C++、ASM）。 如果没有通过命令行指定 <code>CMAKE_TOOLCHAIN_FILE</code>， 就自动使用项目里的 toolchain file 并写入 cache。 然后添加通用编译选项（<code>-Wall -Wextra</code>）， 导出 <code>compile_commands.json</code>（给 clangd/IDE 用）， 设置 Debug（<code>-g -O0</code>）和 Release（<code>-O2 -DNDEBUG</code>）模式的编译 flag。 最后通过 <code>add_subdirectory</code> 引入 boot 和 kernel 子目录， 通过 <code>option(CINUX_BUILD_TESTS)</code> 控制 test 子目录的引入， 并通过 <code>include(cmake/qemu.cmake)</code> 引入 QEMU 配置。</p><p><strong>QEMU 配置</strong> (<code>cmake/qemu.cmake</code>)： 使用 <code>find_program</code> 查找 <code>qemu-system-x86_64</code>， 注册 <code>make run</code> 和 <code>make run-debug</code> （带 GDB server）两个自定义 target。 QEMU 的启动参数需要包含： <code>-m</code> 指定内存大小、 <code>-serial stdio</code> 把串口重定向到终端、 <code>-no-reboot</code> 防止 triple fault 后重启、 <code>-debugcon</code> 开启调试端口 （Bochs debug console，I/O port 0xE9）。 <code>make run-debug</code> 会额外加上 <code>-s</code> （开启 GDB stub 在端口 1234） 和 <code>-S</code>（启动后暂停等待 GDB 连接）。 镜像构建脚本 <code>scripts/build_image.sh</code> 被 CMake 调用来把 MBR 裸二进制和其他组件写入磁盘镜像。</p><p><strong>踩坑预警</strong>：CMake 的 toolchain file 在项目第一次 configure 时读取， 之后修改 toolchain file 不会自动生效 ——必须清空 build 目录重新 configure。 另外，<code>CMAKE_SYSTEM_NAME Generic</code> 这个值很关键， 写错（比如写成 <code>Linux</code> 或留空） 会导致 CMake 按照 Linux 程序的方式来配置构建。 笔者有一次手滑写成了 <code>Linux</code>， 后面所有的编译都正常通过， 但链接出来的内核一跑就 triple fault ——排查了整整两个小时才发现是这一个词的问题。</p><p><strong>验证</strong>：在项目根目录创建 build 目录并运行 CMake configure （<code>mkdir build &amp;&amp; cd build &amp;&amp; cmake -DCMAKE_BUILD_TYPE=Debug ..</code>）。 如果一切正常，终端会打印构建配置摘要， 包括编译器路径、构建类型、toolchain file 路径等信息。 确认 CXX Compiler 显示的是系统 GCC 路径， Toolchain 显示的是项目里的 toolchain file。</p><hr><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><h3 id="问题-cmake-configure-失败-报找不到-c-23" tabindex="-1">问题：CMake configure 失败，报找不到 C++23 <a class="header-anchor" href="#问题-cmake-configure-失败-报找不到-c-23" aria-label="Permalink to &quot;问题：CMake configure 失败，报找不到 C++23&quot;">​</a></h3><p>这说明 GCC 版本太旧。C++23 需要至少 GCC 11 （部分特性可能需要更新的版本）。 运行 <code>g++ --version</code> 检查版本号。 如果确实太旧，需要升级 GCC。</p><h3 id="问题-链接-mbr-时报-cannot-find-lgcc-s-或类似的-32-位相关错误" tabindex="-1">问题：链接 MBR 时报 &quot;cannot find -lgcc_s&quot; 或类似的 32 位相关错误 <a class="header-anchor" href="#问题-链接-mbr-时报-cannot-find-lgcc-s-或类似的-32-位相关错误" aria-label="Permalink to &quot;问题：链接 MBR 时报 &quot;cannot find -lgcc_s&quot; 或类似的 32 位相关错误&quot;">​</a></h3><p>这是因为缺少 32 位支持库。 MBR 和后续的 stage2 需要 32 位 ELF 链接（<code>-m elf_i386</code>）， 而 64 位系统默认不带 32 位库。 安装 <code>gcc-multilib</code> 和 <code>g++-multilib</code> 包即可解决。</p><h3 id="问题-改了-toolchain-flag-但-cmake-configure-没有变化" tabindex="-1">问题：改了 toolchain flag 但 CMake configure 没有变化 <a class="header-anchor" href="#问题-改了-toolchain-flag-但-cmake-configure-没有变化" aria-label="Permalink to &quot;问题：改了 toolchain flag 但 CMake configure 没有变化&quot;">​</a></h3><p>CMake 缓存了上一次的 configure 结果。 删掉整个 build 目录（<code>rm -rf build</code>），重新 configure 即可。</p><h3 id="问题-想确认-toolchain-flag-是否真的被注入了" tabindex="-1">问题：想确认 toolchain flag 是否真的被注入了 <a class="header-anchor" href="#问题-想确认-toolchain-flag-是否真的被注入了" aria-label="Permalink to &quot;问题：想确认 toolchain flag 是否真的被注入了&quot;">​</a></h3><p>可以在 build 目录里查看 <code>compile_commands.json</code> （如果项目有源文件的话）， 或者运行 <code>cmake --build build -- VERBOSE=1</code> 查看完整的编译命令， 确认每条编译命令里都带着 <code>-ffreestanding -mno-red-zone</code> 等 flag。</p><hr><h2 id="本篇小结" tabindex="-1">本篇小结 <a class="header-anchor" href="#本篇小结" aria-label="Permalink to &quot;本篇小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>Freestanding 环境</td><td>内核不能用标准库，需要 <code>-ffreestanding -nostdlib</code> 等 flag</td></tr><tr><td>CMake toolchain file</td><td><code>CMAKE_SYSTEM_NAME Generic</code> 告诉 CMake 无目标 OS</td></tr><tr><td><code>_INIT</code> 后缀</td><td>toolchain file 必须用 <code>_INIT</code> 变量，允许用户追加 flag</td></tr><tr><td><code>-mno-red-zone</code></td><td>内核不能有 red zone，中断会覆盖未保存数据</td></tr><tr><td><code>-mcmodel=kernel</code></td><td>代码运行在地址空间最顶端（高半核）</td></tr><tr><td>multilib</td><td>MBR/stage2 需要 32 位 ELF 链接，必须安装 <code>gcc-multilib</code></td></tr><tr><td>构建架构</td><td>三层结构：toolchain file + 顶层 CMakeLists + QEMU 配置</td></tr></tbody></table><p>到这里我们已经完成了开发环境的基础搭建： 安装了全套工具链， 理解了 freestanding 编译的核心概念和每一个 flag 的含义， 配好了 CMake 构建系统的骨架。 下一篇我们将在这个基础上编写第一个 MBR 存根， 把从汇编源码到 QEMU 启动的完整构建链条跑通。</p><hr><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li>在 toolchain file 里加 <code>-Werror</code> 把所有警告变成错误，强制保持代码质量</li><li>把 <code>CMAKE_SYSTEM_NAME</code> 改成 <code>Linux</code> 然后 <code>make</code>，观察链接错误的变化，理解为什么必须是 <code>Generic</code></li><li>写一个 CMake Presets 文件封装 Debug/Release 配置，练习现代 CMake 的工作流</li><li>尝试引入 CMake Presets（<code>CMakePresets.json</code>），把常用的 configure 配置封装成预设，用户只需要 <code>cmake --preset debug</code> 一条命令</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>CMake 官方文档 — <a href="https://cmake.org/cmake/help/latest/manual/cmake-toolchains.7.html" target="_blank" rel="noreferrer">cmake-toolchains(7)</a>: toolchain file 的所有变量和用法</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/Bare_Bones" target="_blank" rel="noreferrer">Bare Bones</a>: freestanding 编译 flag 和交叉编译基础</li><li>Intel SDM — Volume 1: Basic Architecture，<code>-mcmodel=kernel</code> 和 <code>-mno-red-zone</code> 的底层原因</li><li>SerenityOS — <a href="https://github.com/SerenityOS/serenity" target="_blank" rel="noreferrer">CMake 构建系统</a>: 生产级 OS 的 CMake 架构参考</li></ul>`,68)])])}const g=a(s,[["render",d]]);export{h as __pageData,g as default};
